// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.junit.jupiter.api.Test;

class LmdbDistinctCursorSkipSuccessorTest {

	@Test
	void successorQuadAdvancesVarintBoundaries() {
		for (long predicate : new long[] { 240L, 2287L, 3672L, 67823L }) {
			long[] successor = new long[4];
			assertTrue(LmdbDistinctCursorSkipSupport.successorQuad("posc".toCharArray(),
					new long[] { 11L, predicate, 13L, 0L }, 1, successor));
			assertEquals(0L, successor[TripleStore.SUBJ_IDX]);
			assertEquals(predicate + 1L, successor[TripleStore.PRED_IDX]);
			assertEquals(0L, successor[TripleStore.OBJ_IDX]);
			assertEquals(0L, successor[TripleStore.CONTEXT_IDX]);
		}
	}

	@Test
	void successorQuadPreservesSuffixConstantsAfterDistinctPrefix() {
		long[] successor = new long[4];
		assertTrue(LmdbDistinctCursorSkipSupport.successorQuad("posc".toCharArray(),
				new long[] { 11L, 3672L, 93548L, 0L },
				new long[] { -1L, -1L, 93548L, -1L }, 1, successor));
		assertEquals(0L, successor[TripleStore.SUBJ_IDX]);
		assertEquals(3673L, successor[TripleStore.PRED_IDX]);
		assertEquals(93548L, successor[TripleStore.OBJ_IDX]);
		assertEquals(0L, successor[TripleStore.CONTEXT_IDX]);
	}

	@Test
	void successorQuadCarriesCompoundPrefixAndStopsAtMax() {
		long[] successor = new long[4];
		assertTrue(LmdbDistinctCursorSkipSupport.successorQuad("spoc".toCharArray(),
				new long[] { 7L, Long.MAX_VALUE, 13L, 0L }, 2, successor));
		assertEquals(8L, successor[TripleStore.SUBJ_IDX]);
		assertEquals(0L, successor[TripleStore.PRED_IDX]);
		assertEquals(0L, successor[TripleStore.OBJ_IDX]);
		assertEquals(0L, successor[TripleStore.CONTEXT_IDX]);

		assertTrue(!LmdbDistinctCursorSkipSupport.successorQuad("posc".toCharArray(),
				new long[] { 7L, Long.MAX_VALUE, 13L, 0L }, 1, new long[4]));
	}

	@Test
	void suffixComparisonCannotSkipAcrossAnUnboundEarlierComponent() {
		int comparison = LmdbDistinctCursorSkipSupport.compareFixedSuffixAfterPrefix(
				"ospc".toCharArray(),
				new long[] { 11L, 7L, 13L, 0L },
				new long[] { -1L, 5L, -1L, -1L },
				1);

		assertEquals(0, comparison,
				"The unbound subject sorts before the fixed predicate, so the predicate cannot prove that the "
						+ "current object prefix is before or after the requested suffix");
	}
}
